import pdfMake from 'addthaifont-pdfmake';
import 'addthaifont-pdfmake/build/vfs_fonts';
import buddhistEra from 'dayjs/plugin/buddhistEra';
import LocalizedFormat from 'dayjs/plugin/localizedFormat';
import dayjs, { Dayjs } from 'dayjs';

import _ from 'lodash';

pdfMake.fonts = {
  Sarabun: {
    normal: 'Sarabun-Light.ttf',
    bold: 'Sarabun-Regular.ttf',
    italics: 'Sarabun-LightItalic.ttf',
    bolditalics: 'Sarabun-Italic.ttf',
  },
};

dayjs.locale('th');
dayjs.extend(buddhistEra);
dayjs.extend(LocalizedFormat);

// Format number to currency
const formatCurrency = (number) => {
  return number?.toFixed(2)?.replace(/\d(?=(\d{3})+\.)/g, '$&,') || '0.00';
};

// Generate table body rows
const genBody = (rows) => {
  return _.map(rows, (row, index) => [
    { text: index + 1, alignment: 'center' },
    {
      text: [{ text: row?.name || '' }, ,],
    },
    // วันทำงาน
    { text: `${row.totalWork || 0} วัน`, alignment: 'center' },
    // ค่าแรง
    { text: formatCurrency(row?.revenue?.salary || 0), alignment: 'right' },
    // โอที
    { text: formatCurrency(row?.revenue?.overtime || 0), alignment: 'right' },
    // เบี้ยเลี้ยง
    { text: formatCurrency(row?.revenue?.allowances || 0), alignment: 'right' },
    // โบนัส
    { text: formatCurrency(row?.revenue?.bonus || 0), alignment: 'right' },
    // หักภาษี
    {
      text: row.expenses?.tax ? `${formatCurrency(row.expenses?.tax)}` : 0,
      alignment: 'right',
    },
    // ประกันสังคม
    {
      text: row.expenses?.sso ? `${formatCurrency(row.expenses?.sso)}` : 0,
      alignment: 'right',
    },
    // หักอื่นๆ
    {
      text: row.expenses?.other ? `${formatCurrency(row.expenses?.other)}` : 0,
      alignment: 'right',
    },
    // สุทธิ
    { text: formatCurrency(row?.total || 0), alignment: 'right', bold: true },
  ]);
};

// ปรับหัวตาราง
const tableHeader = [
  {
    text: 'ลำดับ',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'พนักงาน',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'วันทำงาน',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'ค่าแรง',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'โอที',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'เบี้ยเลี้ยง',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'โบนัส',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'หักภาษี',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'ประกันสังคม',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'หักอื่นๆ',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
  {
    text: 'สุทธิ',
    fillColor: '#d2d4d2',
    alignment: 'center',
    border: [true, true, true, true],
  },
];

const payrollReport = async (data) => {
  // Format month and year for the header
  const monthYear = dayjs(data?.dateStart).format('MMMM BBBB');

  const genItemBody = genBody(data?.salaryData || []);

  const documentRef = {
    pageSize: 'A4',
    pageOrientation: 'landscape',
    pageMargins: [10, 80, 10, 60],
    defaultStyle: {
      font: 'Sarabun',
      fontSize: 10,
    },
    info: {
      title: 'รายงานการจ่ายค่าแรงประจำเดือน',
      subject: monthYear,
      author: 'MNS System',
    },
    header: function () {
      return {
        margin: [0, 12],
        columns: [
          {
            width: '*',
            text: [
              {
                text: 'รายงานการจ่ายค่าแรงประจำเดือน ',
                style: 'headerPage',
              },
              { text: monthYear, style: 'headerPage' },
            ],
            alignment: 'center',
            border: [false, false, false, false],
          },
        ],
      };
    },
    content: [
      {
        text:
          'ช่วงวันที่ ' +
          `${dayjs(data?.dateStart).format('DD/MM/BBBB')} - ${dayjs(
            data?.dateEnd,
          ).format('DD/MM/BBBB')}`,
        margin: [0, 0, 0, 4],
      },
      {
        text:
          'ประเภท ' +
          `${
            data?.role_type === 'DAILY' ? 'พนักงานรายวัน' : 'พนักงานรายเดือน'
          }`,
        margin: [0, 0, 0, 4],
      },
      {
        table: {
          alignment: '',
          headerRows: 1,
          widths: [
            '5%', // ลำดับ
            '15%', // พนักงาน
            '8%', // วันทำงาน
            '12%', // ค่าแรง
            '8%', // โอที
            '10%', // เบี้ยเลี้ยง
            '10%', // โบนัส
            '8%', // หักภาษี
            '10%', // ประกันสังคม
            '7%', // หักอื่นๆ
            '7%', // สุทธิ
          ],
          body: [tableHeader, ...genItemBody],
        },
      },
    ],

    footer: function (currentPage, pageCount) {
      return {
        columns: [
          {
            text: 'เอกสารใช้ภายในบริษัทเท่านั้น',
            alignment: 'left',
            fontSize: 8,
            margin: [10, 0, 0, 0],
          },
          {
            text: 'หน้า ' + currentPage.toString() + ' จาก ' + pageCount,
            alignment: 'right',
            fontSize: 8,
            margin: [0, 0, 10, 0],
          },
        ],
      };
    },

    styles: {
      headerPage: {
        fontSize: 16,
        bold: true,
        alignment: 'center',
      },
    },
  };

  pdfMake.createPdf(documentRef).open();
};

export default payrollReport;
